// Snow mountain demo — built on terrain-heightmap atom + mountain-shading branch + existing cloud overlay + atmosphere.
export const render = (ctx) => {
  ctx.fillStyle = '#1f3a5c';
  ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);
  ctx.fillStyle = '#ccc';
  ctx.font = '14px sans-serif';
  ctx.fillText('Himalayas — switch to FLY 3D', 24, 48);
};
